const hevronLuxuryCondos = { type: "property", name: "Hevron Luxury Condos", colorGroup: "gold", price: 180, rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 }, buildCost: { house: 60, hotel: 100 }, houses: 0, hotel: false, ownerIndex: null };
const hevronHiTech = { type: "property", name: "Hevron Hi Tech", colorGroup: "gold", price: 180, rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 }, buildCost: { house: 60, hotel: 100 }, houses: 0, hotel: false, ownerIndex: null };

// --- Board events map ---
const boardEvents = {
  1: { type: "property", card: schemYosephGardens },
  3: { type: "property", card: schemRoyalEstates },
  4: { type: "property", card: schemDreamResorts },
  7: { type: "property", card: ephraimHilltops },
  11: { type: "property", card: gushKatif },
  12: { type: "property", card: neveDekalim },
  14: { type: "property", card: ganOr },
  28: { type: "property", card: jerusalemHillsOrchard },
  29: { type: "property", card: jerusalemHills },
  35: { type: "property", card: hevronElonMamrei },
  37: { type: "property", card: hevronLuxuryCondos },
  38: { type: "property", card: hevronHiTech },
};


// --- Players ---
const initialPlayers = [
  { name: "Sam", position: 0, money: 5000 },
  { name: "Jill", position: 0, money: 5000 },
  { name: "Mark", position: 0, money: 5000 },
  { name: "Jim", position: 0, money: 5000 },
];

function App() {
  const [players, setPlayers] = useState(initialPlayers);
  const [currentPlayer, setCurrentPlayer] = useState(0);
  const [dice, setDice] = useState([1, 1]);
  const [showMannaModal, setShowMannaModal] = useState(false);
  const [showRescueModal, setShowRescueModal] = useState(false);
  const [rescueInfo, setRescueInfo] = useState({});

  // Pass these setters to MannaFoodsModal for rescue logic
  const mannaFoodsModalProps = {
    open: showMannaModal,
    onClose: () => setShowMannaModal(false),
    currentPlayer: players[currentPlayer],
    players,
    setPlayers,
    setRescueInfo,
    setShowRescueModal
  };

  // --- Roll Dice ---
  const rollDice = () => {
    const d1 = Math.floor(Math.random() * 6) + 1;
    const d2 = Math.floor(Math.random() * 6) + 1;
    setDice([d1, d2]);

    movePlayer(currentPlayer, d1 + d2);
  };

  // --- Move Player ---
  const movePlayer = (playerIndex, steps) => {
    let newPlayers = [...players];
    let player = { ...newPlayers[playerIndex] };
    player.position = (player.position + steps) % 40;
    newPlayers[playerIndex] = player;
    setPlayers(newPlayers);

    // Check board event
    const event = boardEvents[player.position];
    if (event && event.type === "property") {
      handleProperty(playerIndex, event.card);
    }
  };

  // --- Handle Property ---
  const handleProperty = (playerIndex, property) => {
    let player = { ...players[playerIndex] };
    let newPlayers = [...players];

    if (property.ownerIndex === null) {
      // Player can buy
      if (player.money >= property.price) {
        player.money -= property.price;
        property.ownerIndex = playerIndex;
        newPlayers[playerIndex] = player;
        setPlayers(newPlayers);
        alert(`${player.name} bought ${property.name} for $${property.price}`);
      }
    } else if (property.ownerIndex !== playerIndex) {
      // Pay rent
      let rent = property.rent.base;
      let owner = newPlayers[property.ownerIndex];

      if (player.money >= rent) {
        player.money -= rent;
        owner.money += rent;
      } else {
        // Trigger Rescue
        setRescueInfo({ payer: playerIndex, payee: property.ownerIndex, amount: rent });
        setShowRescueModal(true);
      }

      newPlayers[playerIndex] = player;
      newPlayers[property.ownerIndex] = owner;
      setPlayers(newPlayers);
    }
  };

  // --- Handle Rescue Payment ---
  const handleRescue = (success) => {
    let newPlayers = [...players];
    const { payer, payee, amount } = rescueInfo;

    if (success) {
      // Full payment allowed
      newPlayers[payer].money += amount;
      alert(`${players[payer].name} rescued with $${amount}`);
    } else {
      alert(`${players[payer].name} could not be rescued!`);
    }

    setPlayers(newPlayers);
    setShowRescueModal(false);
  };

  // --- Manna Foods Trigger ---
  const triggerMannaFoods = () => {
    setShowMannaModal(true);
  };


  return (
    <div style={styles.container}>
      <h1>TorahPoly Monopoly</h1>

      {/* Players List */}
      <div>
        <h2>Players</h2>
        <ul>
          {players.map((p, i) => (
            <li key={i} style={{ color: p.color || "black", fontWeight: i === currentPlayer ? "bold" : "normal" }}>
              {p.name} - Money: ${p.money}, Position: {p.position}
            </li>
          ))}
        </ul>
      </div>

      {/* Board */}
      <div style={{ position: "relative", display: "inline-block" }}>
        <img src={boardImage} alt="Board" style={{ width: 800, height: 800, border: "2px solid #000" }} />
        {players.map((p, idx) => {
          const pos = boardPositions[p.position % boardPositions.length];
          return (
            <div
              key={idx}
              style={{
                position: "absolute",
                left: pos.x - 12,
                top: pos.y - 12,
                width: 24,
                height: 24,
                borderRadius: "50%",
                backgroundColor: p.color || "black",
                border: "2px solid gold",
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
                color: "#fff",
                fontWeight: "bold",
              }}
            >
              {idx + 1}
            </div>
          );
        })}
      </div>

      {/* Dice */}
      <div style={{ marginTop: 20 }}>
        <h2>Roll Dice</h2>
        <div>
          <button onClick={rollDice} style={styles.button}>
            Roll Dice
          </button>
        </div>
        <p>
          Dice: {dice[0]} & {dice[1]}
        </p>
      </div>

      {/* Manna Foods Modal */}
      <MannaFoodsModal {...mannaFoodsModalProps} />

      {/* Rescue Modal */}
      <RescueModal
        open={showRescueModal}
        onClose={() => setShowRescueModal(false)}
        currentPlayer={players[rescueInfo.payer] || {}}
        rentAmount={rescueInfo.amount || 0}
        players={players}
        setPlayers={setPlayers}
      />
    </div>
  );
};

// --- Styles ---
const styles = {
  container: { fontFamily: "Arial, sans-serif", padding: 20, textAlign: "center" },
  button: { padding: "10px 20px", margin: "5px", fontSize: 16, borderRadius: 6, cursor: "pointer", backgroundColor: "#007bff", color: "#fff", border: "none" },
};

// --- Modal Styles ---
const modalStyles = {
  overlay: { position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 1000 },
  modal: { backgroundColor: "#fff", padding: 30, borderRadius: 12, minWidth: 300, maxWidth: "90%", textAlign: "center", boxShadow: "0 5px 15px rgba(0,0,0,0.3)" },
  button: { margin: "8px 5px", padding: "8px 15px", borderRadius: 6, border: "none", backgroundColor: "#007bff", color: "#fff", fontSize: 14, cursor: "pointer" },
};


// --- Manna Foods Modal ---
function MannaFoodsModal({ open, onClose, currentPlayer, players, setPlayers, setRescueInfo, setShowRescueModal }) {
  if (!open) return null;

  const handlePay = () => {
    const amountStr = prompt("Enter the amount to pay for Manna Foods:");
    const amount = parseInt(amountStr);
    if (isNaN(amount) || amount <= 0) {
      alert("Invalid amount.");
      return;
    }

    if (currentPlayer.money < amount) {
      // Trigger rescue if player cannot pay
      const index = players.findIndex(p => p.name === currentPlayer.name);
      if (index >= 0) {
        setRescueInfo({ payer: index, amount });
        setShowRescueModal(true);
      }
      onClose();
      return;
    }

    // Deduct money from current player
    const updatedPlayers = players.map(p =>
      p.name === currentPlayer.name ? { ...p, money: p.money - amount } : p
    );
    setPlayers(updatedPlayers);
    alert(`${currentPlayer.name} paid $${amount} for Manna Foods!`);
    onClose();
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>Manna Foods</h2>
        <p>Pay for the Manna Foods Banquet.</p>
        <button style={modalStyles.button} onClick={handlePay}>Pay</button>
        <button style={modalStyles.button} onClick={onClose}>Cancel</button>
      </div>
    </div>
  );
}

// --- Rescue Modal ---
function RescueModal({ open, onClose, currentPlayer, rentAmount, players, setPlayers }) {
  if (!open) return null;

  const handleRescue = () => {
    const rescuers = players.filter(p => p.name !== currentPlayer.name);
    if (rescuers.length === 0) {
      alert("No other players to rescue!");
      return;
    }

    const rescuerNames = rescuers.map((p, i) => `${i + 1}: ${p.name}`).join("\n");
    const choice = parseInt(prompt(`Who wants to rescue ${currentPlayer.name}?\n${rescuerNames}\nEnter number:`));
    if (isNaN(choice) || choice < 1 || choice > rescuers.length) return alert("Invalid selection.");
    const rescuer = rescuers[choice - 1];

    const amountStr = prompt(`How much money will ${rescuer.name} give to ${currentPlayer.name}? (Max $${rescuer.money})`);
    const amount = parseInt(amountStr);
    if (isNaN(amount) || amount <= 0 || amount > rescuer.money) return alert("Invalid amount.");

    const updatedPlayers = players.map(p => {
      if (p.name === currentPlayer.name) return { ...p, money: p.money + amount };
      if (p.name === rescuer.name) return { ...p, money: p.money - amount };
      return p;
    });
    setPlayers(updatedPlayers);
    alert(`${rescuer.name} gave $${amount} to ${currentPlayer.name}!`);
    onClose();
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>Rescue Needed!</h2>
        <p>{currentPlayer.name} cannot pay ${rentAmount}.</p>
        <button style={modalStyles.button} onClick={handleRescue}>Rescue</button>
        <button style={modalStyles.button} onClick={onClose}>Cancel</button>
      </div>
    </div>
  );
}

export default App;
